namespace sv_9b29bbd521344a47b7224d9f5a765019.Services;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

@using sv_9b29bbd521344a47b7224d9f5a765019.Services

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <span class="text-muted small">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft" disabled="@IsMoving">
                    &larr; Move Left
                </button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight" disabled="@IsMoving">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@using sv_9b29bbd521344a47b7224d9f5a765019.Services

<div class="d-flex flex-wrap gap-3 mb-3 p-3 bg-light rounded">
    <div><strong>Total:</strong> @Tasks.Count</div>
    <div><strong>To Do:</strong> @Tasks.Count(t => t.Status == "To Do")</div>
    <div><strong>In Progress:</strong> @Tasks.Count(t => t.Status == "In Progress")</div>
    <div><strong>Done:</strong> @Tasks.Count(t => t.Status == "Done")</div>
    <div class="@(OverdueCount > 0 ? "text-danger" : "")">
        <strong>Overdue:</strong> @OverdueCount
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();

    private int OverdueCount => Tasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done");
}

@using sv_9b29bbd521344a47b7224d9f5a765019.Services

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="HasLeftColumn"
                          ShowMoveRight="HasRightColumn"
                          IsMoving="movingTaskId == task.Id"
                          OnMoveLeft="() => HandleMoveLeft(task)"
                          OnMoveRight="() => HandleMoveRight(task)" />
            }
        </div>
        <div class="card-footer">
            @if (showAddForm)
            {
                <AddTaskForm OnSave="HandleSave" OnCancel="() => showAddForm = false" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showAddForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool HasLeftColumn { get; set; }
    [Parameter] public bool HasRightColumn { get; set; }
    [Parameter, EditorRequired] public EventCallback<(int TaskId, string NewStatus)> OnTaskMoved { get; set; }
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnTaskCreated { get; set; }

    private bool showAddForm;
    private int? movingTaskId;

    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    private async Task HandleMoveLeft(TaskItem task)
    {
        var idx = Array.IndexOf(Statuses, ColumnName);
        if (idx <= 0) return;
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task.Id, Statuses[idx - 1]));
        movingTaskId = null;
    }

    private async Task HandleMoveRight(TaskItem task)
    {
        var idx = Array.IndexOf(Statuses, ColumnName);
        if (idx < 0 || idx >= Statuses.Length - 1) return;
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task.Id, Statuses[idx + 1]));
        movingTaskId = null;
    }

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) formData)
    {
        await OnTaskCreated.InvokeAsync((formData.Title, formData.Assignee, formData.Priority, formData.DueDate, ColumnName));
        showAddForm = false;
    }
}

@page "/board"
@using sv_9b29bbd521344a47b7224d9f5a765019.Services
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        @foreach (var (status, index) in Statuses.Select((s, i) => (s, i)))
        {
            <BoardColumn ColumnName="@status"
                         Tasks="GetFilteredTasksForStatus(status)"
                         HasLeftColumn="index > 0"
                         HasRightColumn="index < Statuses.Length - 1"
                         OnTaskMoved="HandleTaskMoved"
                         OnTaskCreated="HandleTaskCreated" />
        }
    </div>
}

@code {
    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private List<TaskItem> GetFilteredTasksForStatus(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }

        return tasks.ToList();
    }

    private async Task HandleTaskMoved((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            var task = allTasks.FirstOrDefault(t => t.Id == args.TaskId);
            if (task is not null)
            {
                allTasks = allTasks
                    .Select(t => t.Id == args.TaskId ? t with { Status = args.NewStatus } : t)
                    .ToList();
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            allTasks.Add(newTask with { Status = args.Status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

